import{_ as a,o as t,c as b,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const S=JSON.parse('{"title":"饲主","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/魔法武器/6.可升级/饲主.md","filePath":"4.资源分区/7.物品与装备/2.武器/魔法武器/6.可升级/饲主.md"}'),o={name:"4.资源分区/7.物品与装备/2.武器/魔法武器/6.可升级/饲主.md"};function p(d,e,l,i,_,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"饲主",tabindex:"-1"},[n("饲主 "),r("a",{class:"header-anchor",href:"#饲主","aria-label":'Permalink to "饲主"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"新世短歌033")])])],-1),s('<h1 id="饲主-1" tabindex="-1">饲主 <a class="header-anchor" href="#饲主-1" aria-label="Permalink to &quot;饲主&quot;">​</a></h1><p>饲主<br> 你并非出身黑帮，但你用手中的金钱控制了他们，让他们成为你的野狗，去啃咬你的敌人。而你，只是拿着这根镶嵌着玉石的黑檀木手杖，在明面上做一个绅士。<br> 合法证件<br> 250<br> 你准备了合法证件，拥有一个明面的合法身份，这是动用你的猎犬的先决条件。拥有合法证件才能购买和使用饲主系列武器，这是饲主的使用前置，而非低级，所以不能用来差价升级饲主。</p><p>D级：收买<br> D+500<br> 别紧张，不需要费劲寻找那些穷凶极恶之人或是自私自利之人，只需要从普通市民中找一些有着家室与责任，只有微薄的工资的家伙，给他们一份特别工作就好了。<br> 体积3 法器 法术强度6 <br> 内奸：让他们先将周围的消息进行汇报吧，起码还有点用。持握这柄手杖时只有你能看见的黑影会源源不断地向你传达周围的信息，这是一个D级特异本质的侦测能力,基于视觉。<br> 先机：利用信息的优势，用最低的价格收买，用对方最重要之物威胁，用最快的速度扩张自己的地盘，或许血腥罪恶，但领先一步才是重要的事情。你的先攻额外投掷一个10面骰</p><p>C级：契约<br> C+1000<br> 我们是一所合法的顾问公司，干着合法的勾当，使用的是在自由的国度秉承双方自由而签订的合法契约，虽然并不公正，但这都是对方“自愿”签订的，不是吗。<br> 体积3 法器 法术强度11 <br> 顾问公司：我们是合法公司，他们也是合法雇员，虽然工作没什么变化。继承【内奸】与【先机】的效果<br> 友善交易：我们是顾问公司，自然会温和地向我们的“合作对象”提出建议，如果对方同意签下不是很平等的契约，只需要被榨干就能留下性命。如果对方拒绝，那么后果自负。你进行的施法攻击可以改为令目标使用意志豁免应对。</p><p>B级：银弹<br> B+2000<br> 我的双手一尘不染，你的店铺被人打砸，你的账册被人抢夺，这真是太不幸了，我向你表示哀悼，但，这和我又有什么关系呢？<br> 体积3 法器 法术强度18<br> 暴力事件：最近经常有些暴力事件，当然，这和本公司没有任何关系。持握这柄手杖时只有你能看见的黑影会不择手段，源源不断地向你传达周围的信息，现在这是一个B级特异本质的侦测能力，同样基于听觉，因为他们开始使用暴力。<br> 合法竞争：这次招标只有我一个人出价，真是偶然。只有你能看见的黑影们开始不分敌我地干扰其他人，确保你获得绝对的优势，这相对来说意味着你的先攻额外投掷两个10面骰。<br> 银弹警告：做生意，平安无事才是最重要的，你说对吗？比起直接争夺，先进行威胁才是更有效的选择，你进行的施法攻击可以改为令目标使用意志豁免应对，且你可以令你的施法攻击附带伤害二分之一的恐惧点数。</p><p>A级：优先<br> A+4000<br> 最好的员工，最好的设备，最好的资源，最低廉的工资，我的公司如此优秀，因为我有一切的优先权。<br> 体积3 法器 法术强度27+2附加成功<br> 扎根于此：政府、警察，都是我的人，我的手下在各个街头，对于市民，只要稍加威胁，我就能知道想知道的一切，这里还有什么是我不知晓的？持握这柄手杖时只有你能看见的黑影与更多的弱小的白影会源源不断地向你传递周围的信息，现在有了“群众基础”的你有了A级特异本质的侦测能力，基于听觉。<br> 漆黑幕布：其实现在每个人都知道我是一切的幕后黑手，但他们对我又能做什么？这片天已经被盖上了漆黑幕布，曙光？不会出现。现在你的威胁自然极度高效。你的施法攻击可以改为令目标使用意志豁免应对，且你可以令你的施法攻击附带等同于伤害的恐惧点数。<br> 最优先权：即使工资不高，员工也别无选择，其他企业不敢收容他们，即使出价极低，拍卖人也别无选择，没有其他人会出价，一切资源都由本公司最先挑选，其他人，也许能拾得一些残羹冷炙，这取决于我的心情。没有你的许可其他人不允许与你争夺，你的先攻额外投掷4个十面骰，受到你进行的施法攻击的目标需要用意志豁免对抗伤害，若失败，则其受到你的威胁，其意志豁免在当前场景中承受劣化3，这是一个A级别、影响心灵来源的效果。<br> 釜底抽薪：总会有些刺头想要挑衅我的领域，不过无所谓，稍加等待，然后从他的薄弱之处发出最根本的攻击。当你对任意目标进行了施法攻击后，只有你能看见的黑影开始自动搜索目标的资料，在你的下个回合开始后，你对包含该目标在内的敌人进行施法攻击时，可以令该攻击忽略闪避或盔甲防御中的一种（需在回合开始时选择、切换忽略的防御类型），这是个A级别信息来源的效果。</p><p>S级：宿命<br> S+8000<br> 当企业不断扩张，涉黑的影子终将成为对手的目标，成为把柄，当走狗变得无用甚至对饲主有害，那么被抛弃便是其宿命。<br> 体积3 法器 法术强度38+8附加成功<br> 抛弃：特殊的，S级饲主不能直接由低等级的饲主差价升级，而是作为低级原价70%的抵扣（例如A+4000的A级相当于B+6000分用来差价升级）。或者你也可以选择先支付差价，但在下一场影片结束时才能通过演变升级为S级饲主（例如你有A级饲主，你可以支付A+4000的差价升级为S级，但其效果仍然为A级效果，在下次影片结束时才会正式升级为S级，获得S级对应的效果，在计算评级时，此时视为S级资源）<br> 正大光明：抛弃黑色的走狗，作为代替，有了更为方便的走狗。持握这柄手杖时只有你能看见的白色人影们会源源不断地向你传递周围的信息，洗白的你能利用公权力与你广大的下属职工，现在你拥有S级特异本质的侦测能力，基于听觉。<br> 白璧无瑕：我仍然会用威胁的手段，丢弃走狗的我使用合法合规的手段进行竞争，至少在法律条文上是合法合规的，若有人想与我竞争，现在你们要如何应对没有污点的我呢？你进行的施法攻击可以改为令目标使用意志豁免应对，且你可以令你的施法攻击附带等同于伤害的四档恐惧点数。<br> 总有门路：如果对方使用暴力，我便鼓吹扫黑除恶，若对方正当竞争，便叫质检部门对他们好好检查，走狗被抛弃，这里是一个秩序的世界，在秩序的世界里，总有秩序的手段清理我讨厌的家伙。每回合一次，你可以自由动作选择任意一种防御类型，你在本回合进行的施法攻击可以忽略这种防御，这是一个S级别、信息来源的效果。<br> 高优先级：虽然没法像以前一样通过走狗的震慑肆无忌惮，但凭借关系网在商业竞争中能更快的得到先机，有舍亦有得。你的先攻额外投掷8个先攻骰。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const A=a(o,[["render",p]]);export{S as __pageData,A as default};
